import { useState } from 'react';

function NameForm() {
  const [name, setName] = useState('');

  return (
    <div>
      <label>
        Name:
        <input 
          type="text" 
          value={name} 
          onChange={e => setName(e.target.value)} 
        />
      </label>
      <p>Your name is: {name}</p>
    </div>
  );
}
